Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? resolvedInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded => {resolvedInfo!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a source-gen context that only knows about Person.
var restrictedOptions = new JsonSerializerOptions();
restrictedOptions.TypeInfoResolver = SmallContext.Default;

if (restrictedOptions.TryGetTypeInfo<Person>(out _))
{
    Console.WriteLine("TryGetTypeInfo<Person> on restricted options => found");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> on restricted options => NOT found (no exception!)");
}

